#!/usr/bin/env node
/**
 * Generate nginx redirect rules for legacy LLM routes.
 * Output: nginx location blocks that return 301 to course-scoped URLs.
 * Usage: node scripts/generate-nginx-redirects.mjs > nginx-redirects.conf
 */

import { loadPrimaryCourse } from './lib/course-package-source.mjs';

const { modules } = loadPrimaryCourse();

const lines = [
  '# Auto-generated redirect rules for legacy LLM routes.',
  '# Include this in your nginx server block.',
  '# Generated by: node scripts/generate-nginx-redirects.mjs',
  '',
];

// Module pages: /zh/s01/ -> /zh/courses/llm-fundamentals/s01/
for (const { data: mod } of modules) {
  const slug = mod.id;
  lines.push(`location = /zh/${slug}/ { return 301 /zh/courses/llm-fundamentals/${slug}/; }`);
  lines.push(`location = /zh/${slug}  { return 301 /zh/courses/llm-fundamentals/${slug}/; }`);
}

lines.push('');

// Layers and timeline
lines.push('location = /zh/layers/   { return 301 /zh/courses/llm-fundamentals/layers/; }');
lines.push('location = /zh/layers    { return 301 /zh/courses/llm-fundamentals/layers/; }');
lines.push('location = /zh/timeline/ { return 301 /zh/courses/llm-fundamentals/timeline/; }');
lines.push('location = /zh/timeline  { return 301 /zh/courses/llm-fundamentals/timeline/; }');

lines.push('');

// Courses catalog -> hub
lines.push('location = /zh/courses/  { return 301 /zh/; }');
lines.push('location = /zh/courses   { return 301 /zh/; }');

lines.push('');

console.log(lines.join('\n'));
